class Solution:
    def earliestFinishTime(self, landStartTime, landDuration, waterStartTime, waterDuration):
        landEnd = min(s + d for s, d in zip(landStartTime, landDuration))
        waterEnd = min(s + d for s, d in zip(waterStartTime, waterDuration))
        best = float('inf')
        for ws, wd in zip(waterStartTime, waterDuration):
            best = min(best, max(landEnd, ws) + wd)
        for ls, ld in zip(landStartTime, landDuration):
            best = min(best, max(waterEnd, ls) + ld)
        return best

