var earliestFinishTime = function(landStartTime, landDuration, waterStartTime, waterDuration) {
    let landEnd = Infinity, waterEnd = Infinity;
    for (let i = 0; i < landStartTime.length; i++) landEnd = Math.min(landEnd, landStartTime[i] + landDuration[i]);
    for (let j = 0; j < waterStartTime.length; j++) waterEnd = Math.min(waterEnd, waterStartTime[j] + waterDuration[j]);
    let best = Infinity;
    for (let j = 0; j < waterStartTime.length; j++) best = Math.min(best, Math.max(landEnd, waterStartTime[j]) + waterDuration[j]);
    for (let i = 0; i < landStartTime.length; i++) best = Math.min(best, Math.max(waterEnd, landStartTime[i]) + landDuration[i]);
    return best;
};
